import React from 'react';
import {useEffect, useState, useParams} from 'react';
import {useLoaderData} from 'react-router';

const UserDetail = () => {
    const user = useLoaderData();

    return (
        <div>
            <h1>{user.name}</h1>
            <p>Email: {user.email}</p>
            <p>Phone: {user.phone}</p>
        </div>
    );
}

export default UserDetail;
